INSERT INTO `parawa6_content` VALUES (1,109,'Experience the Joy of Thai Cooking Classes Across Thailand','thai-cooking-classes-in-thailand','\r\n\r\n\r\n  <meta charset=\"UTF-8\">\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1, shrink-to-fit=no\">\r\n  <meta name=\"rights\" content=\"All rights reserved by Cook It Thailand 2024\">\r\n  <meta name=\"robots\" content=\"max-snippet:-1, max-image-preview:large, max-video-preview:-1\">\r\n  <title>Cook It Thailand | Thai Cooking Classes</title>\r\n\r\n  <!-- Twitter Card -->\r\n  <meta name=\"twitter:title\" content=\"Cook It Thailand | Thai Cooking Classes\">\r\n  <meta name=\"twitter:description\" content=\"Experience the authentic flavors of Thai cuisine on cooking classes in Thailand.\">\r\n  <meta name=\"twitter:image\" content=\"https://cookitthailand.com/images/Logo/cook-it-animated-logo.gif\">\r\n  <meta name=\"twitter:card\" content=\"summary_large_image\">\r\n\r\n  <!-- Open Graph -->\r\n  <meta property=\"og:title\" content=\"Cook It Thailand | Thai Cooking Classes\">\r\n  <meta property=\"og:description\" content=\"Experience the authentic flavors of Thai cuisine on cooking classes in Thailand.\">\r\n  <meta property=\"og:image\" content=\"https://cookitthailand.com/images/Logo/cook-it-animated-logo.gif\">\r\n  <meta property=\"og:image:alt\" content=\"Cook It Thailand Logo\">\r\n  <meta property=\"og:url\" content=\"https://cookitthailand.com/\">\r\n  <meta property=\"og:type\" content=\"website\">\r\n\r\n  <!-- Favicons & App Icons -->\r\n  <link rel=\"icon\" type=\"image/png\" sizes=\"32x32\" href=\"/favicon-32x32.png\">\r\n  <link rel=\"icon\" type=\"image/png\" sizes=\"16x16\" href=\"/favicon-16x16.png\">\r\n  <link rel=\"icon\" type=\"image/x-icon\" href=\"/favicon.ico\">\r\n  <link rel=\"apple-touch-icon\" sizes=\"180x180\" href=\"/apple-touch-icon.png\">\r\n\r\n  <!-- Structured Data for Google Site Branding -->\r\n  <script type=\"application/ld+json\">\r\n  {\r\n    \"@context\": \"https://schema.org\",\r\n    \"@type\": \"Organization\",\r\n    \"name\": \"Cook It Thailand\",\r\n    \"url\": \"https://cookitthailand.com\",\r\n    \"logo\": \"https://cookitthailand.com/images/Logo/cook-it-animated-logo.gif\"\r\n  }\r\n  </script>\r\n\r\n\r\n\r\n  <h1>Thai Cooking Classes in Thailand</h1>\r\n  <p>Take the taste of Thailand home with you! Sign up for an exciting Thai cooking class today.<br>\r\n    <img src=\"images/Pictures/Cook_It/Thai_Cooking_Classes.webp\" width=\"500\" height=\"500\" alt=\"Thai Cooking Classes\" style=\"margin: 10px; float: right;\">\r\n  </p>\r\n  <hr>\r\n\r\n  <h3>Discover the Fun of Thai Cooking Across Thailand!</h3>\r\n  <p>Welcome to a world where flavors come alive! Our Thai cooking classes are designed for everyone—from enthusiastic novices to budding chefs looking to enhance their culinary skills. Join us in some of Thailand\'s most vibrant destinations for a delightful cooking adventure.</p>\r\n\r\n  <h4>Our Mission</h4>\r\n  <p>We’re passionate about sharing the rich, mouthwatering flavors and traditions of Thai cuisine with food lovers from around the globe. Our mission is to connect you with talented chefs and authentic cooking schools, ensuring your culinary journey is not only educational but incredibly enjoyable!</p>\r\n  <hr>\r\n\r\n  <h3>Meet Our Chefs</h3>\r\n  <ul>\r\n    <li>\r\n      <p><strong>Koh Tao - Chef Parawan</strong><br>\r\n        With over 15 years of cooking experience on Koh Tao, Parawan opened her cooking class in 2019. Her expertise and love for Thai cuisine shine through in every dish.</p>\r\n    </li>\r\n    <li>\r\n      <p><strong>Koh Phangan - TBC</strong><br>Add intro about the Chef.</p>\r\n    </li>\r\n    <li>\r\n      <p><strong>Koh Samui - TBC</strong><br>Add intro about the Chef.</p>\r\n    </li>\r\n  </ul>\r\n  <hr>\r\n\r\n  <h3>Explore Our Classes</h3>\r\n  <p>Get ready for hands-on fun! Join our lively classes led by skilled chefs who will guide you through traditional recipes and techniques. Enjoy market tours, engaging cooking sessions, and immerse yourself in the heart of Thai culture.</p>\r\n\r\n  <h4>Class Options</h4>\r\n  <p>Participants can choose from a variety of dishes available for each class. You can view the complete menu options <a href=\"locations/koh-tao/class-menu-options\" target=\"_blank\" rel=\"noopener\">here</a>.</p>\r\n  <ul>\r\n    <li><strong>Private Classes:</strong> Choose any 3 dishes from the menu.</li>\r\n    <li><strong>Group Classes:</strong> The first person to book selects 3 dishes; others will follow that menu.</li>\r\n  </ul>\r\n  <hr>\r\n\r\n  <h3>Locations &amp; Pricing</h3>\r\n  <p>We’re expanding our offerings across Thailand! Below are our current locations and pricing:</p>\r\n  <ul>\r\n    <li><strong>Koh Tao</strong>\r\n      <ul>\r\n        <li>Group Class: <strong>1,500 Baht per person</strong></li>\r\n      </ul>\r\n    </li>\r\n    <li><strong>Koh Phangan</strong>\r\n      <ul>\r\n        <li>Group Class: <strong>1,800 Baht per person</strong></li>\r\n      </ul>\r\n    </li>\r\n    <li><strong>Koh Samui</strong>\r\n      <ul>\r\n        <li>Group Class: <strong>2,200 Baht per person</strong></li>\r\n      </ul>\r\n    </li>\r\n  </ul>\r\n  <p><em>Pricing for private classes is available upon request.</em></p>\r\n  <hr>\r\n\r\n  <h3>Why Choose Us?</h3>\r\n  <ul>\r\n    <li><strong>Authenticity:</strong> Learn from passionate local chefs eager to share their culinary heritage.</li>\r\n    <li><strong>Flexibility:</strong> Classes available at various locations and times to fit your travel plans.</li>\r\n    <li><strong>Community:</strong> Join a vibrant community of fellow cooking enthusiasts and create lasting memories.</li>\r\n  </ul>\r\n  <hr>\r\n\r\n  <div class=\"wf-columns wf-columns-stack-medium\" data-wf-columns=\"1\">\r\n    <div class=\"wf-column\">\r\n      <p><img src=\"images/Pictures/Cook_It/Padi_Thai.webp\" width=\"300\" height=\"300\" alt=\"Padi Thai\" style=\"margin: 10px auto; display: block;\"></p>\r\n    </div>\r\n    <div class=\"wf-column\">\r\n      <p><img src=\"images/Pictures/Cook_It/Green_Curry.webp\" width=\"300\" height=\"300\" alt=\"Green Curry\" style=\"display: block; margin: 10px auto;\"></p>\r\n    </div>\r\n  </div>\r\n\r\n  <h3>Book Your Class Today!</h3>\r\n  <p>Are you ready to kickstart your culinary adventure? Booking a class through our website is easy! Select your destination, choose a class that piques your interest, and prepare for a delightful cooking experience.</p>\r\n  <p>For any questions or specific requests, please feel free to reach out via our contact page.</p>\r\n  <hr>\r\n\r\n  <h3>Join Us Today!</h3>\r\n  <p>Dive into a journey filled with flavors and techniques that will enhance your cooking skills. Discover the joy of Thai cuisine and make your travels unforgettable!</p>\r\n\r\n','',1,2,'2024-02-29 03:08:00',970,'','2025-04-20 23:49:04',970,NULL,NULL,'2024-02-29 03:08:00',NULL,'{\"image_intro\":\"\",\"image_intro_alt\":\"\",\"float_intro\":\"\",\"image_intro_caption\":\"\",\"image_fulltext\":\"\",\"image_fulltext_alt\":\"\",\"float_fulltext\":\"\",\"image_fulltext_caption\":\"\"}','{\"urla\":\"\",\"urlatext\":\"\",\"targeta\":\"\",\"urlb\":\"\",\"urlbtext\":\"\",\"targetb\":\"\",\"urlc\":\"\",\"urlctext\":\"\",\"targetc\":\"\"}','{\"article_layout\":\"\",\"show_title\":\"1\",\"link_titles\":\"\",\"show_tags\":\"\",\"show_intro\":\"\",\"info_block_position\":\"\",\"info_block_show_title\":\"\",\"show_category\":\"\",\"link_category\":\"\",\"show_parent_category\":\"\",\"link_parent_category\":\"\",\"show_author\":\"\",\"link_author\":\"\",\"show_create_date\":\"\",\"show_modify_date\":\"\",\"show_publish_date\":\"\",\"show_item_navigation\":\"\",\"show_hits\":\"\",\"show_noauth\":\"\",\"urls_position\":\"\",\"alternative_readmore\":\"\",\"article_page_title\":\"\",\"show_publishing_options\":\"\",\"show_article_options\":\"\",\"show_urls_images_backend\":\"\",\"show_urls_images_frontend\":\"\",\"helix_ultimate_image\":\"\",\"helix_ultimate_image_alt_txt\":\"\",\"helix_ultimate_article_format\":\"standard\",\"helix_ultimate_audio\":\"\",\"helix_ultimate_gallery\":\"\",\"helix_ultimate_video\":\"\"}',111,6,'Thai cooking classes','Experience authentic Thai cooking classes across Thailand. Join passionate chefs, explore local flavors, and elevate your culinary skills in vibrant locations!',1,23490,'{\"robots\":\"\",\"author\":\"\",\"rights\":\"\"}',1,'*',''),(44,184,'Join Our Koh Samui Thai Cooking Class for Authentic Flavors','koh-samui-thai-cooking-class','<p><meta charset=\"UTF-8\" /><meta content=\"width=device-width, initial-scale=1.0\" name=\"viewport\" />\r\n<title>Thai Cooking Class Koh Samui | Culinary Adventure in Thailand</title>\r\n</p>\r\n<!-- Open Graph Metadata -->\r\n<p><meta content=\"Thai Cooking Class Koh Samui | Culinary Adventure in Thailand\" property=\"og:title\" /><meta content=\"website\" property=\"og:type\" /><meta content=\"https://cookitthailand.com/koh-samui\" property=\"og:url\" /><meta content=\"https://cookitthailand.com/images/Koh_Samui/Thai_Cooking_Class_Koh_Samui.webp\" property=\"og:image\" /><meta content=\"Experience the rich flavors of Thai cuisine with our Cooking Class Koh Samui. Perfect for beginners and seasoned cooks!\" property=\"og:description\" /></p>\r\n<!-- Twitter Card Metadata -->\r\n<p><meta content=\"summary_large_image\" name=\"twitter:card\" /><meta content=\"Thai Cooking Class Koh Samui | Culinary Adventure in Thailand\" name=\"twitter:title\" /><meta content=\"Experience the rich flavors of Thai cuisine with our Cooking Class Koh Samui. Perfect for beginners and seasoned cooks!\" name=\"twitter:description\" /><meta content=\"https://cookitthailand.com/images/Koh_Samui/Thai_Cooking_Class_Koh_Samui.webp\" name=\"twitter:image\" /></p>\r\n<h1>Cooking Class Koh Samui</h1>\r\n<p><img src=\"images/Koh_Samui/Thai_Cooking_Class_Koh_Samui.webp\" width=\"500\" height=\"500\" alt=\"Thai Cooking Class Koh Samui\" style=\"margin: 10px; float: right;\" /></p>\r\n<h2>Immerse Yourself in a Culinary Adventure on Koh Samui</h2>\r\n<p>Experience the rich flavors of Thai cuisine with our Cooking Class Koh Samui, offering a unique culinary adventure that explores the heart of Thai food culture. Our classes are designed to provide an engaging cooking experience, perfect for both beginners and seasoned cooks alike.</p>\r\n<h3>Why Choose Our Thai Cooking Class?</h3>\r\n<p>Our hands-on cooking class offers guidance from expert chefs who have a deep passion for food. You\'ll learn from experienced chefs, including master chefs and executive chefs, who will share their impressive cooking skills and techniques. This is an opportunity to step into the world of Thai culinary arts and discover the secrets of creating authentic dishes.</p>\r\n<h3>Explore the Flavors of Thailand</h3>\r\n<ul>\r\n<li><strong>Thai Herbs and Fresh Produce:</strong> Dive into the vibrant world of Thai herbs and fresh produce. Learn how to incorporate these ingredients into your cooking to enhance the flavors of your dishes.</li>\r\n<li><strong>Traditional Thai Dishes:</strong> Master traditional recipes such as banana in coconut milk, a delightful dessert that showcases the use of milk in dessert and fresh produce.</li>\r\n</ul>\r\n<h3>Class Offerings</h3>\r\n<ul>\r\n<li><strong>Private Classes:</strong> Opt for exclusive cooking classes where you can enjoy personalized attention and a tailored cooking session.</li>\r\n<li><strong>Cooking Challenges:</strong> Participate in exciting cooking challenges that test your skills and creativity.</li>\r\n<li><strong>Comprehensive Program:</strong> Our cooking class program covers a wide array of dishes, providing a comprehensive recipe book and bonus recipes to continue your culinary journey at home.</li>\r\n</ul>\r\n<h3>What to Expect</h3>\r\n<p>Our lovely cooking class on Ko Samui offers an extensive menu, ensuring you get a taste of various Thai dishes. With a focus on food for people, you\'ll explore food culture and learn valuable cooking techniques that elevate your culinary skills.</p>\r\n<ul>\r\n<li><strong>Market Tour Everyday:</strong> Start your day with a market tour to select the freshest ingredients, ensuring your dishes are made with organic food and fresh market produce.</li>\r\n<li><strong>Journey with Confidence:</strong> Our classes are designed to provide you with the confidence to recreate these dishes at home, transforming your cooking abilities.</li>\r\n</ul>\r\n<h3>Join Us for a Transformative Journey</h3>\r\n<p>Located in the picturesque setting of Koh Samui Thailand, our cooking classes promise a transformative journey into the world of Thai cuisine. Enjoy the guidance of talented chefs as you embark on this culinary adventure. Whether you\'re a local or visiting from afar, book your class at Buddha Samui and take the first step in your journey with confidence.</p>\r\n<p>For more information, contact us today or book in for a class below. We look forward to welcoming you to our Cooking Class Koh Samui for an unforgettable experience!</p>\r\n<p>Not sure if you have time to fit in a cooking class on Koh Samui? Then if you are heading to <a href=\"index.php?option=com_content&amp;view=article&amp;id=50:cooking-class-koh-phangan&amp;catid=12:koh-phangan&amp;Itemid=393\" title=\"Thai Cooking Class in Koh Phangan\">Koh Phangan</a> or <a href=\"index.php?option=com_content&amp;view=article&amp;id=52:koh-tao-thai-cooking-class&amp;catid=19:koh-tao&amp;Itemid=394\" title=\"Thai Cooking Class in Koh Tao\">Koh Tao</a> and maybe book onto a course there.</p>\r\n<!-- Embedded booking begin -->\r\n<div class=\"embedded-booking\" data-url=\"https://cookitthailand.wlbookings.com\" data-query=\"&amp;t=s&amp;uuid=80cf5dee-7300-47dc-ad59-3cf647460053\" data-employee=\"samui-cook-it\" data-lang=\"en\" data-autoresize=\"1\" data-showsidebar=\"1\" style=\"min-width: 320px; height: 768px;\">&nbsp;</div>\r\n<script type=\"text/javascript\" src=\"https://cookitthailand.wlbookings.com/embed.js\" async=\"async\"></script>\r\n<!-- Embedded booking end -->','',1,13,'2024-12-18 00:47:23',970,'','2025-04-03 13:44:15',970,NULL,NULL,'2024-12-18 00:47:23',NULL,'{\"image_intro\":\"\",\"image_intro_alt\":\"\",\"float_intro\":\"\",\"image_intro_caption\":\"\",\"image_fulltext\":\"\",\"image_fulltext_alt\":\"\",\"float_fulltext\":\"\",\"image_fulltext_caption\":\"\"}','{\"urla\":\"\",\"urlatext\":\"\",\"targeta\":\"\",\"urlb\":\"\",\"urlbtext\":\"\",\"targetb\":\"\",\"urlc\":\"\",\"urlctext\":\"\",\"targetc\":\"\"}','{\"article_layout\":\"\",\"show_title\":\"\",\"link_titles\":\"\",\"show_tags\":\"\",\"show_intro\":\"\",\"info_block_position\":\"\",\"info_block_show_title\":\"\",\"show_category\":\"\",\"link_category\":\"\",\"show_parent_category\":\"\",\"link_parent_category\":\"\",\"show_author\":\"\",\"link_author\":\"\",\"show_create_date\":\"\",\"show_modify_date\":\"\",\"show_publish_date\":\"\",\"show_item_navigation\":\"\",\"show_hits\":\"\",\"show_noauth\":\"\",\"urls_position\":\"\",\"alternative_readmore\":\"\",\"article_page_title\":\"\",\"show_publishing_options\":\"\",\"show_article_options\":\"\",\"show_urls_images_backend\":\"\",\"show_urls_images_frontend\":\"\",\"helix_ultimate_image\":\"\",\"helix_ultimate_image_alt_txt\":\"\",\"helix_ultimate_article_format\":\"standard\",\"helix_ultimate_audio\":\"\",\"helix_ultimate_gallery\":\"\",\"helix_ultimate_video\":\"\"}',13,1,'Thai Cooking Class Koh Samui','Join our Thai Cooking Class in Koh Samui and learn to create authentic dishes with fresh ingredients. Experience the flavors of Thailand today!',1,1576,'{\"robots\":\"\",\"author\":\"\",\"rights\":\"\"}',0,'*',''),(50,191,'Explore the Delicious Culinary Offerings of Koh Phangan','cooking-class-koh-phangan','<p><meta charset=\"UTF-8\" /><meta content=\"width=device-width, initial-scale=1.0\" name=\"viewport\" />\r\n<title>Thai Cooking Class Koh Phangan | Learn Authentic Thai Cuisine</title>\r\n</p>\r\n<!-- Open Graph Metadata -->\r\n<p><meta content=\"Thai Cooking Class Koh Phangan | Discover Thai Culinary Delights\" property=\"og:title\" /><meta content=\"website\" property=\"og:type\" /><meta content=\"https://cookitthailand.com/koh-phangan\" property=\"og:url\" /><meta content=\"https://cookitthailand.com/images/Koh_Phangan/Koh_Phangan_Cooking_Class.webp\" property=\"og:image\" /><meta content=\"Join our Thai Cooking Class in Koh Phangan and experience the vibrant flavors of Thai cuisine. Perfect for all skill levels!\" property=\"og:description\" /></p>\r\n<!-- Twitter Card Metadata -->\r\n<p><meta content=\"summary_large_image\" name=\"twitter:card\" /><meta content=\"Thai Cooking Class Koh Phangan | Discover Thai Culinary Delights\" name=\"twitter:title\" /><meta content=\"Join our Thai Cooking Class in Koh Phangan and experience the vibrant flavors of Thai cuisine. Perfect for all skill levels!\" name=\"twitter:description\" /><meta content=\"https://cookitthailand.com/images/Koh_Phangan/Koh_Phangan_Cooking_Class.webp\" name=\"twitter:image\" /></p>\r\n<h1>Koh Phangan On Koh Phangan | Discover Thai Culinary Delights</h1>\r\n<p>Embark on a culinary adventure with our Koh Phangan cooking class, where you will dive into the vibra <img src=\"images/Koh_Phangan/Koh_Phangan_Cooking_Class.webp\" width=\"350\" height=\"350\" alt=\"Thai Cooking Class Koh Phangan\" style=\"margin: 10px; float: right;\" /> nt flavors of Thai cuisine. Our cooking classes are designed to enhance your cooking skills and provide an immersive experience in the rich Thai food culture of Koh Phangan.</p>\r\n<h2>Why Choose Our Cooking Class in Koh Phangan?</h2>\r\n<p>Our Koh Phangan Cooking Classes offer comprehensive lessons perfect for both beginners and experienced cooks. With a focus on fresh ingredients, traditional techniques, and authentic recipes, our classes are ideal for food lovers eager to explore the diverse world of Thai dishes.</p>\r\n<h3>Explore Traditional Thai Cuisine</h3>\r\n<ul>\r\n<li><strong>Signature Dishes:</strong> Learn to prepare famous foods like Massaman Curry, Pad Thai, and Green Curry using traditional Thai cooking methods. Our classes also cover the creation of delicious coconut milk dishes such as Thai Green Curry and Panaeng Curry.</li>\r\n<li><strong>Curry Pastes from Scratch:</strong> Master the art of <a href=\"https://www.bbc.co.uk/food/recipes/greencurrypaste_67789\" title=\"Making Thai Green Curry Paste\" target=\"_blank\" rel=\"noopener\">making curry paste</a>, bean paste, chilli paste, and fish paste from scratch with authentic Thai ingredients.</li>\r\n<li><strong>Market Experience:</strong> Start your day with a market visit to select the freshest produce, an integral part of our holistic food preparation process.</li>\r\n</ul>\r\n<h3>What to Expect from Our Cooking Classes</h3>\r\n<p>Our cooking class program provides a hands-on learning experience, focusing on developing your cooking expertise and skills. At your own cooking station, engage in cooking lessons that emphasize creating dishes from scratch. Our fun afternoon sessions ensure you have an amazing time while honing your culinary prowess.</p>\r\n<h3>Class Options and Offerings</h3>\r\n<ul>\r\n<li><strong>Private Classes:</strong> Enjoy personalized attention with private lessons tailored to your specific culinary interests.</li>\r\n<li><strong>Group Sessions:</strong> Join others in a fun setting, perfect for everyday people looking to expand their cooking knowledge.</li>\r\n<li><strong>Combination Classes:</strong> Experience a combination of cooking class techniques for a well-rounded culinary education.</li>\r\n</ul>\r\n<h3>Food Preferences and Dietary Considerations</h3>\r\n<p>We accommodate diverse food preferences and food intolerances, offering gluten-free recipes and alternative ingredients for those with specific dietary needs. Our focus on the flavor of taste and harmony of tastes ensures that every dish reflects the amazing food culture of Thailand.</p>\r\n<h3>Book Your Cooking Class On Koh Phangan Today</h3>\r\n<p>Join us for an incredible cooking class experience on the beautiful island of Koh Phangan. Whether you’re interested in private classes or group sessions, our classes promise a fantastic time filled with delicious food and lifelong culinary skills. For more information or to secure your spot, please contact us today. We look forward to welcoming you to our Cooking Class Koh Phangan for a journey into the heart of Thai cuisine!</p>\r\n<p>Can\'t fit a cooking class into your schedule on Koh Phangan? How about <a href=\"index.php?option=com_content&amp;view=article&amp;id=44:koh-samui-thai-cooking-class&amp;catid=13:koh-samui&amp;Itemid=406\" title=\"Cooking Class Koh Samui\">Koh Samui</a> or <a href=\"index.php?option=com_content&amp;view=article&amp;id=52:koh-tao-thai-cooking-class&amp;catid=19:koh-tao&amp;Itemid=394\" title=\"Cooking Class Koh Tao\" target=\"_blank\">Koh Tao</a>?</p>','',1,12,'2024-12-18 01:37:17',970,'','2025-04-03 13:45:43',970,NULL,NULL,'2024-12-18 01:37:17',NULL,'{\"image_intro\":\"\",\"image_intro_alt\":\"\",\"float_intro\":\"\",\"image_intro_caption\":\"\",\"image_fulltext\":\"\",\"image_fulltext_alt\":\"\",\"float_fulltext\":\"\",\"image_fulltext_caption\":\"\"}','{\"urla\":\"\",\"urlatext\":\"\",\"targeta\":\"\",\"urlb\":\"\",\"urlbtext\":\"\",\"targetb\":\"\",\"urlc\":\"\",\"urlctext\":\"\",\"targetc\":\"\"}','{\"article_layout\":\"\",\"show_title\":\"\",\"link_titles\":\"\",\"show_tags\":\"\",\"show_intro\":\"\",\"info_block_position\":\"\",\"info_block_show_title\":\"\",\"show_category\":\"\",\"link_category\":\"\",\"show_parent_category\":\"\",\"link_parent_category\":\"\",\"show_author\":\"\",\"link_author\":\"\",\"show_create_date\":\"\",\"show_modify_date\":\"\",\"show_publish_date\":\"\",\"show_item_navigation\":\"\",\"show_hits\":\"\",\"show_noauth\":\"\",\"urls_position\":\"\",\"alternative_readmore\":\"\",\"article_page_title\":\"\",\"show_publishing_options\":\"\",\"show_article_options\":\"\",\"show_urls_images_backend\":\"\",\"show_urls_images_frontend\":\"\",\"helix_ultimate_image\":\"\",\"helix_ultimate_image_alt_txt\":\"\",\"helix_ultimate_article_format\":\"standard\",\"helix_ultimate_audio\":\"\",\"helix_ultimate_gallery\":\"\",\"helix_ultimate_video\":\"\"}',23,1,'Cooking Class Koh Phangan','Join our Cooking Class Koh Phangan to explore vibrant Thai cuisine. Enhance your cooking skills with an immersive experience in rich Thai food culture.',1,1050,'{\"robots\":\"\",\"author\":\"\",\"rights\":\"\"}',0,'*',''),(52,193,'Experience Authentic Thai Cuisine in Our Koh Tao Cooking Class','koh-tao-thai-cooking-class','<meta charset=\"UTF-8\" /><meta content=\"width=device-width, initial-scale=1, shrink-to-fit=no\" name=\"viewport\" />\r\n<title>Thai Cooking Classes on Koh Tao | Cook It Thailand</title>\r\n<!-- Canonical URL -->\r\n<p>&nbsp;</p>\r\n<!-- Robots and Rights --> <meta content=\"max-snippet:-1, max-image-preview:large, max-video-preview:-1\" name=\"robots\" /><meta content=\"All rights reserved by Parawan Thai Home Cooking Classes 2024\" name=\"rights\" /><!-- Twitter Card --> <meta content=\"summary_large_image\" name=\"twitter:card\" /><meta content=\"Parawan\'s Thai Home Cooking Class\" name=\"twitter:title\" /><meta content=\"Experience the authentic flavors of Thai cuisine with my cooking classes on Koh Tao.\" name=\"twitter:description\" /><meta content=\"https://cookitthailand.com/images/Pictures/Roof-top-Thai-Cooking-School-Koh-Tao.webp\" name=\"twitter:image\" /><!-- Open Graph --> <meta content=\"Parawan\'s Thai Home Cooking Classes\" property=\"og:title\" /><meta content=\"website\" property=\"og:type\" /><meta content=\"https://cookitthailand.com/locations/koh-tao\" property=\"og:url\" /><meta content=\"https://cookitthailand.com/images/Pictures/Roof-top-Thai-Cooking-School-Koh-Tao.webp\" property=\"og:image\" /><meta content=\"Parawan\'s Thai Home Cooking Classes on Koh Tao\" property=\"og:site_name\" /><meta content=\"Experience the authentic flavours of Thai cuisine with my cooking classes on Koh Tao.\" property=\"og:description\" /><meta content=\"cookingclasskohtao\" property=\"fb:page_id\" /><meta content=\"contact@cookitthailand.com\" property=\"og:email\" /><meta content=\"+66 875114654\" property=\"og:phone_number\" /><meta content=\"10.10221\" property=\"og:latitude\" /><meta content=\"99.83392\" property=\"og:longitude\" /><meta content=\"13/82 Moo 1\" property=\"og:street-address\" /><meta content=\"Koh Tao\" property=\"og:locality\" /><meta content=\"Surat Thani\" property=\"og:region\" /><meta content=\"84360\" property=\"og:postal-code\" /><meta content=\"Thailand\" property=\"og:country-name\" /><meta content=\"en_US\" property=\"og:locale\" /><!-- Optional: Favicon -->\r\n<h1 style=\"text-align: center;\">Come and take a Thai Cooking Class with me on Koh Tao</h1>\r\n<p>Welcome to Cook It Thailand! If you\'re looking for an authentic and engaging Thai cooking experience, you\'ve come to the right place. Our Thai Cooking Classes on Koh Tao offer a unique opportunity to immerse yourself in Thailand\'s rich culinary culture while enjoying the island\'s relaxed, tropical vibes.</p>\r\n<p><img src=\"images/Logo/Parawan-Thai-Cooking-Class-Koh-Tao.png\" alt=\"Parawan Thai Cooking Class Koh Tao\" width=\"300\" height=\"299\" style=\"margin: 10px 5px; float: left;\" /></p>\r\n<p><strong>Meet Parawan—Your Local Chef Extraordinaire:</strong> Parawan is the heart and soul of our Thai Cooking Classes on Koh Tao. With years of experience and a deep love for Thai cuisine, she brings both expertise and warmth to every class.</p>\r\n<p><strong>What to Expect in My Classes:</strong></p>\r\n<ul>\r\n<li>A warm welcome and introduction to Thai cooking traditions</li>\r\n<li>Ingredient explanation and techniques</li>\r\n<li>Step-by-step guidance for three classic Thai dishes</li>\r\n<li>Enjoy the delicious food you’ve cooked!</li>\r\n</ul>\r\n<p><strong>Why Koh Tao?</strong> Koh Tao isn’t just known for its crystal-clear waters and vibrant marine life—it’s a hidden gem for food lovers. Whether you’re traveling solo, with friends, or family, our classes are a must-do activity on the island.</p>\r\n<p><strong>Classes Beyond Koh Tao:</strong> We’ve partnered with chefs on Koh Samui and Koh Phangan to bring you the same great experience. [Placeholder for Koh Samui and Koh Phangan links]</p>\r\n<p><strong>Over 400 Glowing Reviews:</strong> With rave reviews from students around the world, our classes are a top-rated experience on Koh Tao.</p>\r\n<p><strong>Join me in the Kitchen:</strong> Ready to create unforgettable memories and delicious dishes? Book your spot today and let’s cook together!</p>\r\n<p>We can adapt recipes to be vegetarian, vegan, or pescatarian. Please let us know about any allergies or preferences in advance.</p>\r\n<p>You can see the dish options on the <a href=\"index.php?option=com_content&amp;view=article&amp;id=39:parawans-thai-cooking-class-menu-for-online-and-courses-on-koh-tao&amp;catid=9:thai-food\">Cooking Course Menu</a> page.</p>\r\n<h3 style=\"text-align: center;\"><strong>Group Classes with Pre-Selected Menus</strong></h3>\r\n<p><iframe src=\"https://calendar.google.com/calendar/embed?src=vagl6soli7lh9n9lhvhir0en8o@group.calendar.google.com&amp;ctz=Asia/Bangkok&amp;mode=AGENDA\" width=\"100%\" height=\"600\" frameborder=\"0\" scrolling=\"no\" sandbox=\"allow-same-origin allow-scripts allow-popups\"></iframe></p>\r\n<h3 style=\"text-align: center;\"><strong>Pick your class and book below</strong></h3>\r\n<p><iframe src=\"https://parawansthaicookingclass.trafft.com/booking-embedded?t=s&amp;uuid=591acad5-dc14-461f-9a06-48fe85e0ecc6\" width=\"100%\" height=\"600\" frameborder=\"0\" scrolling=\"no\" sandbox=\"allow-same-origin allow-scripts allow-popups\"></iframe></p>','',1,19,'2024-02-29 03:08:00',970,'','2025-04-26 21:47:44',970,NULL,NULL,'2024-02-29 03:08:00',NULL,'{\"image_intro\":\"\",\"image_intro_alt\":\"\",\"float_intro\":\"\",\"image_intro_caption\":\"\",\"image_fulltext\":\"\",\"image_fulltext_alt\":\"\",\"float_fulltext\":\"\",\"image_fulltext_caption\":\"\"}','{\"urla\":\"\",\"urlatext\":\"\",\"targeta\":\"\",\"urlb\":\"\",\"urlbtext\":\"\",\"targetb\":\"\",\"urlc\":\"\",\"urlctext\":\"\",\"targetc\":\"\"}','{\"article_layout\":\"\",\"show_title\":\"1\",\"link_titles\":\"\",\"show_tags\":\"\",\"show_intro\":\"\",\"info_block_position\":\"\",\"info_block_show_title\":\"\",\"show_category\":\"\",\"link_category\":\"\",\"show_parent_category\":\"\",\"link_parent_category\":\"\",\"show_author\":\"\",\"link_author\":\"\",\"show_create_date\":\"\",\"show_modify_date\":\"\",\"show_publish_date\":\"\",\"show_item_navigation\":\"\",\"show_hits\":\"\",\"show_noauth\":\"\",\"urls_position\":\"\",\"alternative_readmore\":\"\",\"article_page_title\":\"\",\"show_publishing_options\":\"\",\"show_article_options\":\"\",\"show_urls_images_backend\":\"\",\"show_urls_images_frontend\":\"\",\"helix_ultimate_image\":\"\",\"helix_ultimate_image_alt_txt\":\"\",\"helix_ultimate_article_format\":\"standard\",\"helix_ultimate_audio\":\"\",\"helix_ultimate_gallery\":\"\",\"helix_ultimate_video\":\"\"}',106,8,'Cooking Class Koh Tao','Join our Cooking Class Koh Tao at Parawan\'s Thai Home Cooking Classes. Enhance your cooking skills while enjoying an immersive experience in authentic food culture.',1,1594,'{\"robots\":\"\",\"author\":\"\",\"rights\":\"\"}',0,'*','');
